}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly IDataView _trainingData;
    private readonly string[] _classLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _trainingData = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainModel();
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered class labels so we can map Score[] indices to names
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(_trainingData.Schema)["Score"]
            .GetSlotNames(ref labelBuffer);
        _classLabels = labelBuffer.DenseValues()
            .Select(v => v.ToString())
            .ToArray();
    }

    private ITransformer TrainModel()
    {
        // Combine Subject + Description into a single text feature, plus Priority
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        return pipeline.Fit(_trainingData);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticket = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticket);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationResponse Evaluate()
    {
        var predictions = _model.Transform(_trainingData);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var perClass = new List<PerClassMetric>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            perClass.Add(new PerClassMetric
            {
                ClassName = i < _classLabels.Length ? _classLabels[i] : $"Class_{i}",
                Precision = metrics.ConfusionMatrix.PerClassPrecision[i],
                Recall = metrics.ConfusionMatrix.PerClassRecall[i],
                F1Score = 2 * metrics.ConfusionMatrix.PerClassPrecision[i]
                            * metrics.ConfusionMatrix.PerClassRecall[i]
                          / (metrics.ConfusionMatrix.PerClassPrecision[i]
                            + metrics.ConfusionMatrix.PerClassRecall[i])
            });
        }

        return new EvaluationResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(_classifier.Predict(request));
    }

    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        return Ok(_classifier.Evaluate());
    }
}

